139	    // -------------------------------------------------------------------------
140	    // Partition label extraction (full depth)
141	    // -------------------------------------------------------------------------
142	
143	    private void extractLabels(JsonNode node, String prefix, Map<String, String> out) {
144	        if (node == null || node.isMissingNode()) return;
145	
146	        String path      = node.path("path").asText(null);
147	        String attribute = node.path("attribute").asText(null);
148	        if (path == null || attribute == null) return;
149	
150	        String labelIn  = prefix + attribute + "_in_"  + path;
151	        String labelOut = prefix + attribute + "_out_" + path;
152	
153	        JsonNode withPath    = node.path("withPath");
154	        JsonNode withoutPath = node.path("withoutPath");
155	
156	        assignPages(withPath, labelIn, out);
157	        if (withPath.has("path") && withPath.has("attribute")) {
158	            extractLabels(withPath, labelIn + "_", out);
159	        }
160	
161	        assignPages(withoutPath, labelOut, out);
162	        if (withoutPath.has("path") && withoutPath.has("attribute")) {
163	            extractLabels(withoutPath, labelOut + "_", out);
164	        }
165	    }
166	
167	    private void assignPages(JsonNode node, String label, Map<String, String> out) {
168	        JsonNode pages = node.path("pages");
169	        if (pages.isArray()) {
170	            for (JsonNode page : pages) {
171	                out.put(page.asText(), label);
172	            }
173	        }
174	    }
