176	    // -------------------------------------------------------------------------
177	    // Partition label extraction at a given depth (for best-aggregation sweep)
178	    // -------------------------------------------------------------------------
179	
180	    private Map<String, String> extractAtDepth(JsonNode node, int maxDepth) {
181	        Map<String, String> out = new LinkedHashMap<>();
182	        extractAtDepthRec(node, "", 0, maxDepth, out);
183	        return out;
184	    }
185	
186	    private void extractAtDepthRec(JsonNode node, String prefix, int depth, int maxDepth,
187	                                   Map<String, String> out) {
188	        if (node == null || node.isMissingNode()) return;
189	
190	        String path      = node.path("path").asText(null);
191	        String attribute = node.path("attribute").asText(null);
192	        if (path == null || attribute == null) return;
193	
194	        String labelIn  = prefix + attribute + "_in_"  + path;
195	        String labelOut = prefix + attribute + "_out_" + path;
196	
197	        boolean atLeaf = (maxDepth > 0 && depth + 1 >= maxDepth);
198	
199	        JsonNode withPath    = node.path("withPath");
200	        JsonNode withoutPath = node.path("withoutPath");
201	
202	        if (atLeaf) {
203	            collectAll(withPath,    labelIn,  out);
204	            collectAll(withoutPath, labelOut, out);
205	        } else {
206	            assignPages(withPath, labelIn, out);
207	            if (withPath.has("path") && withPath.has("attribute")) {
208	                extractAtDepthRec(withPath, labelIn + "_", depth + 1, maxDepth, out);
209	            }
210	            assignPages(withoutPath, labelOut, out);
211	            if (withoutPath.has("path") && withoutPath.has("attribute")) {
212	                extractAtDepthRec(withoutPath, labelOut + "_", depth + 1, maxDepth, out);
213	            }
214	        }
215	    }
216	
217	    private void collectAll(JsonNode node, String label, Map<String, String> out) {
218	        if (node == null || node.isMissingNode()) return;
219	        assignPages(node, label, out);
220	        if (node.has("path") && node.has("attribute")) {
221	            JsonNode with    = node.path("withPath");
222	            JsonNode without = node.path("withoutPath");
223	            collectAll(with,    label, out);
224	            collectAll(without, label, out);
225	        }
226	    }
227	
228	    // -------------------------------------------------------------------------
229	    // Metrics
230	    // -------------------------------------------------------------------------
231	
232	    private double pairwiseAgreement(Map<String, String> c1, Map<String, String> c2,
233	                                     List<String> urls) {
234	        int agree = 0, total = 0;
235	        for (int i = 0; i < urls.size(); i++) {
236	            for (int j = i + 1; j < urls.size(); j++) {
237	                boolean sameIn1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
238	                boolean sameIn2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
239	                if (sameIn1 == sameIn2) agree++;
240	                total++;
241	            }
242	        }
243	        return total == 0 ? 0.0 : (double) agree / total;
244	    }
245	
246	    private double adjustedRandIndex(Map<String, String> c1, Map<String, String> c2,
247	                                     List<String> urls) {
248	        int a = 0, b = 0, c = 0, d = 0;
249	        for (int i = 0; i < urls.size(); i++) {
250	            for (int j = i + 1; j < urls.size(); j++) {
251	                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
252	                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
253	                if      ( s1 &&  s2) a++;
254	                else if ( s1 && !s2) b++;
255	                else if (!s1 &&  s2) c++;
256	                else                 d++;
257	            }
258	        }
259	        int nPairs = a + b + c + d;
260	        if (nPairs == 0) return 0.0;
261	
262	        double ri = (double)(a + d) / nPairs;
263	        int n = urls.size();
264	        double t = (double) n * (n - 1) / 2;
265	
266	        Map<String, Long> freq1 = freqMap(c1, urls);
267	        Map<String, Long> freq2 = freqMap(c2, urls);
268	
269	        double expSame = 0;
270	        for (long cnt : freq1.values()) expSame += cnt * (cnt - 1) / 2.0;
271	        for (long cnt : freq2.values()) expSame += cnt * (cnt - 1) / 2.0;
272	        expSame /= (2 * t);
273	
274	        double expRi = expSame * expSame + (1 - expSame) * (1 - expSame);
275	        if (expRi >= 1.0) return 0.0;
276	        return (ri - expRi) / (1 - expRi);
277	    }
278	
279	    private double[] precisionRecall(Map<String, String> c1, Map<String, String> c2,
280	                                     List<String> urls) {
281	        int c1Same = 0, bothSame = 0, c2Same = 0, bothSame2 = 0;
282	        for (int i = 0; i < urls.size(); i++) {
283	            for (int j = i + 1; j < urls.size(); j++) {
284	                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
285	                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
286	                if (s1) { c1Same++;  if (s2) bothSame++;  }
287	                if (s2) { c2Same++;  if (s1) bothSame2++; }
288	            }
289	        }
290	        double precision = c1Same  == 0 ? 0.0 : (double) bothSame  / c1Same;
291	        double recall    = c2Same  == 0 ? 0.0 : (double) bothSame2 / c2Same;
292	        return new double[]{precision, recall};
293	    }
294	
295	    private double[] bestAggregation(JsonNode partitionRoot, Map<String, String> c2,
296	                                     List<String> urlsIntersection) {
297	        double bestF1 = -1;
298	        double bestPrec = 0, bestRec = 0;
299	        int bestDepth = 1;
300	
301	        int[] depths = {1, 2, 3, 4, 5, 6, 7, -1};
302	        for (int depth : depths) {
303	            Map<String, String> c1All = extractAtDepth(partitionRoot, depth);
304	            List<String> urls = new ArrayList<>(c1All.keySet());
305	            urls.retainAll(c2.keySet());
306	            urls.sort(Comparator.naturalOrder());
307	            if (urls.size() < 2) continue;
308	
309	            Map<String, String> c1 = restrict(c1All, urls);
310	            Map<String, String> c2r = restrict(c2, urls);
311	            double[] pr = precisionRecall(c1, c2r, urls);
312	            double f = f1(pr[0], pr[1]);
313	            if (f > bestF1) {
314	                bestF1 = f;
315	                bestPrec = pr[0];
316	                bestRec  = pr[1];
317	                bestDepth = depth;
318	            }
319	        }
320	        return new double[]{bestPrec, bestRec, bestDepth};
321	    }
322	
323	    // -------------------------------------------------------------------------
324	    // Helpers
325	    // -------------------------------------------------------------------------
326	
327	    private double f1(double precision, double recall) {
328	        return (precision + recall) == 0 ? 0.0
329	                : 2 * precision * recall / (precision + recall);
330	    }
331	
332	    private Map<String, String> restrict(Map<String, String> map, List<String> keys) {
333	        Map<String, String> result = new LinkedHashMap<>();
334	        for (String k : keys) result.put(k, map.get(k));
335	        return result;
336	    }
337	
338	    private int distinctCount(Map<String, String> map) {
339	        return new HashSet<>(map.values()).size();
340	    }
341	
342	    private Map<String, Long> freqMap(Map<String, String> clustering, List<String> urls) {
343	        Map<String, Long> freq = new HashMap<>();
344	        for (String url : urls) {
345	            String label = clustering.get(url);
346	            freq.merge(label, 1L, Long::sum);
347	        }
348	        return freq;
349	    }
350	
351	    // -------------------------------------------------------------------------
352	    // Reporting
353	    // -------------------------------------------------------------------------
354	
355	    private void printObjectReport(String objectId, int urlCount,
356	                                   int partitionClusters, int extractorClusters,
357	                                   double agreement, double ari,
358	                                   double precision, double recall, double f1Full,
359	                                   double bestPrec, double bestRec, double bestF1,
360	                                   int bestDepth) {
361	        double f1Gap = (bestF1 - f1Full) * 100;
362	        String depthStr = bestDepth == -1 ? "full" : String.valueOf(bestDepth);
363	        System.out.printf("""
364	                -------------------------------------------------
365	                Object: %s
366	                  URLs (common):   %d
367	                  Partition clusters: %d   Extractor clusters: %d
368	                  Agreement:       %.4f
369	                  ARI:             %.4f
370	                  Precision:       %.4f   Recall:  %.4f   F1: %.4f
371	                  Best agg depth:  %-4s   Prec: %.4f  Rec: %.4f  F1: %.4f  (gap: %+.2f pp)
372	                %n""",
373	                objectId, urlCount,
374	                partitionClusters, extractorClusters,
375	                agreement, ari,
376	                precision, recall, f1Full,
377	                depthStr, bestPrec, bestRec, bestF1, f1Gap);
378	    }
379	
380	    private void printAggregateSummary(List<double[]> metrics) {
381	        if (metrics.isEmpty()) {
382	            System.out.println("No objects evaluated.");
383	            return;
384	        }
385	        int n = metrics.size();
386	        double[] sums = new double[5];
387	        for (double[] m : metrics) for (int i = 0; i < 5; i++) sums[i] += m[i];
388	        System.out.printf("""
389	                =================================================
390	                AGGREGATE SUMMARY (%d object(s))
391	                  Avg Agreement: %.4f
392	                  Avg ARI:       %.4f
393	                  Avg Precision: %.4f
394	                  Avg Recall:    %.4f
395	                  Avg F1:        %.4f
396	                =================================================%n""",
397	                n,
398	                sums[0] / n, sums[1] / n, sums[2] / n, sums[3] / n, sums[4] / n);
399	    }
400	}
