230	    private double adjustedRandIndex(Map<String, String> c1, Map<String, String> c2, List<String> urls) {
231	        int a = 0, b = 0, c = 0, d = 0;
232	        for (int i = 0; i < urls.size(); i++) {
233	            for (int j = i + 1; j < urls.size(); j++) {
234	                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
235	                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
236	                if ( s1 &&  s2) {
237	                    a++;
238	                }
239	                else if (s1) {
240	                    b++;
241	                }
242	                else if (s2) {
243	                    c++;
244	                }
245	                else {
246	                    d++;
247	                }
248	            }
249	        }
250	        int nPairs = a + b + c + d;
251	        if (nPairs == 0) {
252	            return 0.0;
253	        }
254	
255	        double ri = (double)(a + d) / nPairs;
256	        int n = urls.size();
257	        double t = (double) n * (n - 1) / 2;
258	
259	        Map<String, Long> freq1 = freqMap(c1, urls);
260	        Map<String, Long> freq2 = freqMap(c2, urls);
261	
262	        double expSame = 0;
263	        for (long cnt : freq1.values()) expSame += cnt * (cnt - 1) / 2.0;
264	        for (long cnt : freq2.values()) expSame += cnt * (cnt - 1) / 2.0;
265	        expSame /= (2 * t);
266	
267	        double expRi = expSame * expSame + (1 - expSame) * (1 - expSame);
268	        if (expRi >= 1.0) {
269	            return 0.0;
270	        }
271	        return (ri - expRi) / (1 - expRi);
272	    }
