274	    private double[] precisionRecall(Map<String, String> c1, Map<String, String> c2, List<String> urls) {
275	        int c1Same = 0, bothSame = 0, c2Same = 0, bothSame2 = 0;
276	        for (int i = 0; i < urls.size(); i++) {
277	            for (int j = i + 1; j < urls.size(); j++) {
278	                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
279	                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
280	                if (s1) { c1Same++;  if (s2) bothSame++;  }
281	                if (s2) { c2Same++;  if (s1) bothSame2++; }
282	            }
283	        }
284	        double precision = c1Same  == 0 ? 0.0 : (double) bothSame  / c1Same;
285	        double recall    = c2Same  == 0 ? 0.0 : (double) bothSame2 / c2Same;
286	        return new double[]{precision, recall};
287	    }
