package com.meltwater.wrapidity.service.groot.core.partition;

import com.fasterxml.jackson.databind.JsonNode;
import com.meltwater.wrapidity.util.misc.JsonUtils;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVRecord;
import org.junit.jupiter.api.Disabled;
import org.junit.jupiter.api.Test;

import java.io.FileReader;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.*;

/**
 * Compares groot partition clustering against news-ind clustering.
 *
 * Inputs:
 *   - src/test/java/groot_partition/<object_id>.json - groot partition trees
 *   - src/test/java/news-ind-extractors.csv - extractor used for each URL
 *
 * Metrics:
 *   - Pairwise agreement fraction
 *   - Adjusted Rand Index (ARI)
 *   - Pairwise precision / recall / F1
 *   - Best-aggregation F1 (sweeps partition tree depths 1–7 + full)
 */
@Disabled( "This is a manual evaluation, not a unit test.")
public class GrootPartitionsEvaluator {

    private static final String CSV_PATH  = "src/test/resources/partitions_eval/news-ind-extractors.csv";
    private static final String PARTITIONS_DIR = "src/test/resources/partitions_eval/groot_partitions";

    private static final String NO_EXTRACTOR_LABEL = "no_extractor";

    @Test
    void evaluate() throws Exception {
        Path csvPath = Path.of(CSV_PATH);
        Path jsonDir = Path.of(PARTITIONS_DIR);

        Map<String, Map<String, String>> extractorByObject = readExtractorCsv(csvPath);

        System.out.printf("Objects in CSV: %d%n%n", extractorByObject.size());

        List<double[]> allMetrics = new ArrayList<>(); // [agreement, ari, precision, recall, f1]

        for (Map.Entry<String, Map<String, String>> entry : extractorByObject.entrySet()) {
            String objectId = entry.getKey();
            Map<String, String> extractorLabels = entry.getValue();

            Path jsonPath = jsonDir.resolve(objectId + ".json");
            if (!Files.exists(jsonPath)) {
                System.out.printf("[SKIP] %s — no groot output JSON found%n", objectId);
                continue;
            }

            JsonNode root = JsonUtils.getMapper().readTree(jsonPath.toFile());
            JsonNode partitionRoot = root.path("root");
            Map<String, String> partitionLabels = new LinkedHashMap<>();
            extractLabels(partitionRoot, "", partitionLabels);

            List<String> urls = new ArrayList<>(partitionLabels.keySet());
            urls.retainAll(extractorLabels.keySet());
            urls.sort(Comparator.naturalOrder());

            if (urls.size() < 2) {
                System.out.printf("[SKIP] %s — only %d common URL(s)%n", objectId, urls.size());
                continue;
            }

            Map<String, String> c1 = restrict(partitionLabels, urls);
            Map<String, String> c2 = restrict(extractorLabels, urls);

            double agreement = pairwiseAgreement(c1, c2, urls);
            double ari       = adjustedRandIndex(c1, c2, urls);
            double[] pr      = precisionRecall(c1, c2, urls);
            double precision = pr[0], recall = pr[1];
            double f1Full    = f1(precision, recall);

            double[] best    = bestAggregation(partitionRoot, c2);
            double bestPrec  = best[0], bestRec = best[1];
            int bestDepth    = (int) best[2];
            double bestF1    = f1(bestPrec, bestRec);

            printObjectReport(objectId, urls.size(),
                distinctCount(c1), distinctCount(c2),
                agreement, ari, precision, recall, f1Full,
                bestPrec, bestRec, bestF1, bestDepth);

            allMetrics.add(new double[]{agreement, ari, precision, recall, f1Full});
        }

        printAggregateSummary(allMetrics);
    }

    private Map<String, Map<String, String>> readExtractorCsv(Path csvPath) throws Exception {
        Map<String, Map<String, String>> result = new LinkedHashMap<>();
        try (FileReader reader = new FileReader(csvPath.toFile())) {
            Iterable<CSVRecord> records = CSVFormat.DEFAULT
                .builder()
                .setHeader()
                .setSkipHeaderRecord(true)
                .build()
                .parse(reader);
            for (CSVRecord record : records) {
                String objectId      = record.get("object_id");
                String url           = record.get("url");
                String extractorName = record.get("extractor_name");
                String error         = record.get("error");
                if (isExcludedError(error)) {
                    continue;
                }
                String label = (extractorName == null || extractorName.isBlank())
                    ? NO_EXTRACTOR_LABEL : extractorName;
                result.computeIfAbsent(objectId, k -> new LinkedHashMap<>()).put(url, label);
            }
        }
        return result;
    }

    private static boolean isExcludedError(String error) {
        if (error == null || error.isBlank()) {
            return false;
        }
        return error.startsWith("UNEXPECTED_ERROR") || error.startsWith("DOWNLOAD_FAILED");
    }

    private void extractLabels(JsonNode node, String prefix, Map<String, String> out) {
        if (node == null || node.isMissingNode()) {
            return;
        }

        String path = node.path("path").asText(null);
        String attribute = node.path("attribute").asText(null);
        if (path == null || attribute == null) {
            return;
        }

        String labelIn  = prefix + attribute + "_in_"  + path;
        String labelOut = prefix + attribute + "_out_" + path;

        JsonNode withPath    = node.path("withPath");
        JsonNode withoutPath = node.path("withoutPath");

        assignPages(withPath, labelIn, out);
        if (withPath.has("path") && withPath.has("attribute")) {
            extractLabels(withPath, labelIn + "_", out);
        }

        assignPages(withoutPath, labelOut, out);
        if (withoutPath.has("path") && withoutPath.has("attribute")) {
            extractLabels(withoutPath, labelOut + "_", out);
        }
    }

    private void assignPages(JsonNode node, String label, Map<String, String> out) {
        JsonNode pages = node.path("pages");
        if (pages.isArray()) {
            for (JsonNode page : pages) {
                out.put(page.asText(), label);
            }
        }
    }

    private Map<String, String> extractAtDepth(JsonNode node, int maxDepth) {
        Map<String, String> out = new LinkedHashMap<>();
        extractAtDepthRec(node, "", 0, maxDepth, out);
        return out;
    }

    private void extractAtDepthRec(JsonNode node, String prefix, int depth, int maxDepth, Map<String, String> out) {
        if (node == null || node.isMissingNode()) {
            return;
        }

        String path      = node.path("path").asText(null);
        String attribute = node.path("attribute").asText(null);
        if (path == null || attribute == null) {
            return;
        }

        String labelIn  = prefix + attribute + "_in_"  + path;
        String labelOut = prefix + attribute + "_out_" + path;

        boolean atLeaf = (maxDepth > 0 && depth + 1 >= maxDepth);

        JsonNode withPath    = node.path("withPath");
        JsonNode withoutPath = node.path("withoutPath");

        if (atLeaf) {
            collectAll(withPath,    labelIn,  out);
            collectAll(withoutPath, labelOut, out);
        } else {
            assignPages(withPath, labelIn, out);
            if (withPath.has("path") && withPath.has("attribute")) {
                extractAtDepthRec(withPath, labelIn + "_", depth + 1, maxDepth, out);
            }
            assignPages(withoutPath, labelOut, out);
            if (withoutPath.has("path") && withoutPath.has("attribute")) {
                extractAtDepthRec(withoutPath, labelOut + "_", depth + 1, maxDepth, out);
            }
        }
    }

    private void collectAll(JsonNode node, String label, Map<String, String> out) {
        if (node == null || node.isMissingNode()) return;
        assignPages(node, label, out);
        if (node.has("path") && node.has("attribute")) {
            JsonNode with    = node.path("withPath");
            JsonNode without = node.path("withoutPath");
            collectAll(with,    label, out);
            collectAll(without, label, out);
        }
    }

    private double pairwiseAgreement(Map<String, String> c1, Map<String, String> c2,
                                     List<String> urls) {
        int agree = 0, total = 0;
        for (int i = 0; i < urls.size(); i++) {
            for (int j = i + 1; j < urls.size(); j++) {
                boolean sameIn1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
                boolean sameIn2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
                if (sameIn1 == sameIn2) agree++;
                total++;
            }
        }
        return total == 0 ? 0.0 : (double) agree / total;
    }

    private double adjustedRandIndex(Map<String, String> c1, Map<String, String> c2, List<String> urls) {
        int a = 0, b = 0, c = 0, d = 0;
        for (int i = 0; i < urls.size(); i++) {
            for (int j = i + 1; j < urls.size(); j++) {
                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
                if ( s1 &&  s2) {
                    a++;
                }
                else if (s1) {
                    b++;
                }
                else if (s2) {
                    c++;
                }
                else {
                    d++;
                }
            }
        }
        int nPairs = a + b + c + d;
        if (nPairs == 0) {
            return 0.0;
        }

        double ri = (double)(a + d) / nPairs;
        int n = urls.size();
        double t = (double) n * (n - 1) / 2;

        Map<String, Long> freq1 = freqMap(c1, urls);
        Map<String, Long> freq2 = freqMap(c2, urls);

        double expSame = 0;
        for (long cnt : freq1.values()) expSame += cnt * (cnt - 1) / 2.0;
        for (long cnt : freq2.values()) expSame += cnt * (cnt - 1) / 2.0;
        expSame /= (2 * t);

        double expRi = expSame * expSame + (1 - expSame) * (1 - expSame);
        if (expRi >= 1.0) {
            return 0.0;
        }
        return (ri - expRi) / (1 - expRi);
    }

    private double[] precisionRecall(Map<String, String> c1, Map<String, String> c2, List<String> urls) {
        int c1Same = 0, bothSame = 0, c2Same = 0, bothSame2 = 0;
        for (int i = 0; i < urls.size(); i++) {
            for (int j = i + 1; j < urls.size(); j++) {
                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
                if (s1) { c1Same++;  if (s2) bothSame++;  }
                if (s2) { c2Same++;  if (s1) bothSame2++; }
            }
        }
        double precision = c1Same  == 0 ? 0.0 : (double) bothSame  / c1Same;
        double recall    = c2Same  == 0 ? 0.0 : (double) bothSame2 / c2Same;
        return new double[]{precision, recall};
    }

    private double[] bestAggregation(JsonNode partitionRoot, Map<String, String> c2) {
        double bestF1 = -1;
        double bestPrec = 0, bestRec = 0;
        int bestDepth = 1;

        int[] depths = {1, 2, 3, 4, 5, 6, 7, -1};
        for (int depth : depths) {
            Map<String, String> c1All = extractAtDepth(partitionRoot, depth);
            List<String> urls = new ArrayList<>(c1All.keySet());
            urls.retainAll(c2.keySet());
            urls.sort(Comparator.naturalOrder());
            if (urls.size() < 2) {
                continue;
            }

            Map<String, String> c1 = restrict(c1All, urls);
            Map<String, String> c2r = restrict(c2, urls);
            double[] pr = precisionRecall(c1, c2r, urls);
            double f = f1(pr[0], pr[1]);
            if (f > bestF1) {
                bestF1 = f;
                bestPrec = pr[0];
                bestRec  = pr[1];
                bestDepth = depth;
            }
        }
        return new double[]{bestPrec, bestRec, bestDepth};
    }

    private double f1(double precision, double recall) {
        return (precision + recall) == 0 ? 0.0
            : 2 * precision * recall / (precision + recall);
    }

    private Map<String, String> restrict(Map<String, String> map, List<String> keys) {
        Map<String, String> result = new LinkedHashMap<>();
        for (String k : keys) result.put(k, map.get(k));
        return result;
    }

    private int distinctCount(Map<String, String> map) {
        return new HashSet<>(map.values()).size();
    }

    private Map<String, Long> freqMap(Map<String, String> clustering, List<String> urls) {
        Map<String, Long> freq = new HashMap<>();
        for (String url : urls) {
            String label = clustering.get(url);
            freq.merge(label, 1L, Long::sum);
        }
        return freq;
    }

    private void printObjectReport(String objectId, int urlCount, int partitionClusters, int extractorClusters,
                                   double agreement, double ari, double precision, double recall, double f1Full,
                                   double bestPrec, double bestRec, double bestF1, int bestDepth) {
        double f1Gap = (bestF1 - f1Full) * 100;
        String depthStr = bestDepth == -1 ? "full" : String.valueOf(bestDepth);
        System.out.printf("""
                -------------------------------------------------
                Object: %s
                  URLs (common):   %d
                  Partition clusters: %d   Extractor clusters: %d
                  Agreement:       %.4f
                  ARI:             %.4f
                  Precision:       %.4f   Recall:  %.4f   F1: %.4f
                  Best agg depth:  %-4s   Prec: %.4f  Rec: %.4f  F1: %.4f  (gap: %+.2f pp)
                %n""",
            objectId, urlCount,
            partitionClusters, extractorClusters,
            agreement, ari,
            precision, recall, f1Full,
            depthStr, bestPrec, bestRec, bestF1, f1Gap);
    }

    private void printAggregateSummary(List<double[]> metrics) {
        if (metrics.isEmpty()) {
            System.out.println("No objects evaluated.");
            return;
        }
        int n = metrics.size();
        double[] sums = new double[5];
        for (double[] m : metrics) for (int i = 0; i < 5; i++) sums[i] += m[i];
        System.out.printf("""
                =================================================
                AGGREGATE SUMMARY (%d object(s))
                  Avg Agreement: %.4f
                  Avg ARI:       %.4f
                  Avg Precision: %.4f
                  Avg Recall:    %.4f
                  Avg F1:        %.4f
                =================================================%n""",
            n,
            sums[0] / n, sums[1] / n, sums[2] / n, sums[3] / n, sums[4] / n);
    }
}

