/**
 * Groups common URLs by their groot leaf label and keeps only the clusters that mix
 * two or more distinct extractor labels (contamination = irreversible harm).
 *
 * @return groot leaf label -> {extractor label -> page count}, only for contaminated clusters
 */
private Map<String, Map<String, Long>> contaminatedClusters(Map<String, String> partitionLabels,
                                                            Map<String, String> extractorLabels,
                                                            List<String> commonUrls) {
    // groot leaf label -> (extractor label -> count)
    Map<String, Map<String, Long>> byCluster = new LinkedHashMap<>();
    for (String url : commonUrls) {
        String grootLabel     = partitionLabels.get(url);
        String extractorLabel = extractorLabels.get(url);
        byCluster
            .computeIfAbsent(grootLabel, k -> new LinkedHashMap<>())
            .merge(extractorLabel, 1L, Long::sum);
    }

    Map<String, Map<String, Long>> contaminated = new LinkedHashMap<>();
    for (Map.Entry<String, Map<String, Long>> e : byCluster.entrySet()) {
        if (e.getValue().size() >= 2) {
            contaminated.put(e.getKey(), e.getValue());
        }
    }
    return contaminated;
}

/**
 * Prints the per-object harm report and returns the number of pages sitting in a
 * contaminated cluster.
 */
private int printHarmReport(Map<String, Map<String, Long>> contaminated) {
    if (contaminated.isEmpty()) {
        System.out.println("  HARM-FREE (groot is a strict refinement of news-ind)");
        return 0;
    }
    int contaminatedPages = 0;
    System.out.printf("  CONTAMINATION — %d cluster(s) conflate distinct extractors:%n",
        contaminated.size());
    for (Map.Entry<String, Map<String, Long>> e : contaminated.entrySet()) {
        StringBuilder mix = new StringBuilder();
        for (Map.Entry<String, Long> m : e.getValue().entrySet()) {
            if (mix.length() > 0) mix.append(", ");
            mix.append(m.getKey()).append("=").append(m.getValue());
            contaminatedPages += m.getValue();
        }
        System.out.printf("    %s  ->  {%s}%n", e.getKey(), mix);
    }
    return contaminatedPages;
}

