102	    private Map<String, Map<String, String>> readExtractorCsv(Path csvPath) throws Exception {
103	        Map<String, Map<String, String>> result = new LinkedHashMap<>();
104	        try (FileReader reader = new FileReader(csvPath.toFile())) {
105	            Iterable<CSVRecord> records = CSVFormat.DEFAULT
106	                .builder()
107	                .setHeader()
108	                .setSkipHeaderRecord(true)
109	                .build()
110	                .parse(reader);
111	            for (CSVRecord record : records) {
112	                String objectId      = record.get("object_id");
113	                String url           = record.get("url");
114	                String extractorName = record.get("extractor_name");
115	                String error         = record.get("error");
116	                if (isExcludedError(error)) {
117	                    continue;
118	                }
119	                String label = (extractorName == null || extractorName.isBlank())
120	                    ? NO_EXTRACTOR_LABEL : extractorName;
121	                result.computeIfAbsent(objectId, k -> new LinkedHashMap<>()).put(url, label);
122	            }
123	        }
124	        return result;
125	    }
126	
127	    private static boolean isExcludedError(String error) {
128	        if (error == null || error.isBlank()) {
129	            return false;
130	        }
131	        return error.startsWith("UNEXPECTED_ERROR") || error.startsWith("DOWNLOAD_FAILED");
132	    }
