134	    private void extractLabels(JsonNode node, String prefix, Map<String, String> out) {
135	        if (node == null || node.isMissingNode()) {
136	            return;
137	        }
138	
139	        String path = node.path("path").asText(null);
140	        String attribute = node.path("attribute").asText(null);
141	        if (path == null || attribute == null) {
142	            return;
143	        }
144	
145	        String labelIn  = prefix + attribute + "_in_"  + path;
146	        String labelOut = prefix + attribute + "_out_" + path;
147	
148	        JsonNode withPath    = node.path("withPath");
149	        JsonNode withoutPath = node.path("withoutPath");
150	
151	        assignPages(withPath, labelIn, out);
152	        if (withPath.has("path") && withPath.has("attribute")) {
153	            extractLabels(withPath, labelIn + "_", out);
154	        }
155	
156	        assignPages(withoutPath, labelOut, out);
157	        if (withoutPath.has("path") && withoutPath.has("attribute")) {
158	            extractLabels(withoutPath, labelOut + "_", out);
159	        }
160	    }
161	
162	    private void assignPages(JsonNode node, String label, Map<String, String> out) {
163	        JsonNode pages = node.path("pages");
164	        if (pages.isArray()) {
165	            for (JsonNode page : pages) {
166	                out.put(page.asText(), label);
167	            }
168	        }
169	    }
170	
171	    private Map<String, String> extractAtDepth(JsonNode node, int maxDepth) {
172	        Map<String, String> out = new LinkedHashMap<>();
173	        extractAtDepthRec(node, "", 0, maxDepth, out);
174	        return out;
175	    }
176	
177	    private void extractAtDepthRec(JsonNode node, String prefix, int depth, int maxDepth, Map<String, String> out) {
178	        if (node == null || node.isMissingNode()) {
179	            return;
180	        }
181	
182	        String path      = node.path("path").asText(null);
183	        String attribute = node.path("attribute").asText(null);
184	        if (path == null || attribute == null) {
185	            return;
186	        }
187	
188	        String labelIn  = prefix + attribute + "_in_"  + path;
189	        String labelOut = prefix + attribute + "_out_" + path;
190	
191	        boolean atLeaf = (maxDepth > 0 && depth + 1 >= maxDepth);
192	
193	        JsonNode withPath    = node.path("withPath");
194	        JsonNode withoutPath = node.path("withoutPath");
195	
196	        if (atLeaf) {
197	            collectAll(withPath,    labelIn,  out);
198	            collectAll(withoutPath, labelOut, out);
199	        } else {
200	            assignPages(withPath, labelIn, out);
201	            if (withPath.has("path") && withPath.has("attribute")) {
202	                extractAtDepthRec(withPath, labelIn + "_", depth + 1, maxDepth, out);
203	            }
204	            assignPages(withoutPath, labelOut, out);
205	            if (withoutPath.has("path") && withoutPath.has("attribute")) {
206	                extractAtDepthRec(withoutPath, labelOut + "_", depth + 1, maxDepth, out);
207	            }
208	        }
209	    }
210	
211	    private void collectAll(JsonNode node, String label, Map<String, String> out) {
212	        if (node == null || node.isMissingNode()) return;
213	        assignPages(node, label, out);
214	        if (node.has("path") && node.has("attribute")) {
215	            JsonNode with    = node.path("withPath");
216	            JsonNode without = node.path("withoutPath");
217	            collectAll(with,    label, out);
218	            collectAll(without, label, out);
219	        }
220	    }
