222	    private double pairwiseAgreement(Map<String, String> c1, Map<String, String> c2,
223	                                     List<String> urls) {
224	        int agree = 0, total = 0;
225	        for (int i = 0; i < urls.size(); i++) {
226	            for (int j = i + 1; j < urls.size(); j++) {
227	                boolean sameIn1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
228	                boolean sameIn2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
229	                if (sameIn1 == sameIn2) agree++;
230	                total++;
231	            }
232	        }
233	        return total == 0 ? 0.0 : (double) agree / total;
234	    }
235	
236	    private double adjustedRandIndex(Map<String, String> c1, Map<String, String> c2, List<String> urls) {
237	        int a = 0, b = 0, c = 0, d = 0;
238	        for (int i = 0; i < urls.size(); i++) {
239	            for (int j = i + 1; j < urls.size(); j++) {
240	                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
241	                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
242	                if ( s1 &&  s2) {
243	                    a++;
244	                }
245	                else if (s1) {
246	                    b++;
247	                }
248	                else if (s2) {
249	                    c++;
250	                }
251	                else {
252	                    d++;
253	                }
254	            }
255	        }
256	        int nPairs = a + b + c + d;
257	        if (nPairs == 0) {
258	            return 0.0;
259	        }
260	
261	        double ri = (double)(a + d) / nPairs;
262	        int n = urls.size();
263	        double t = (double) n * (n - 1) / 2;
264	
265	        Map<String, Long> freq1 = freqMap(c1, urls);
266	        Map<String, Long> freq2 = freqMap(c2, urls);
267	
268	        double expSame = 0;
269	        for (long cnt : freq1.values()) expSame += cnt * (cnt - 1) / 2.0;
270	        for (long cnt : freq2.values()) expSame += cnt * (cnt - 1) / 2.0;
271	        expSame /= (2 * t);
272	
273	        double expRi = expSame * expSame + (1 - expSame) * (1 - expSame);
274	        if (expRi >= 1.0) {
275	            return 0.0;
276	        }
277	        return (ri - expRi) / (1 - expRi);
278	    }
279	
280	    private double[] precisionRecall(Map<String, String> c1, Map<String, String> c2, List<String> urls) {
281	        int c1Same = 0, bothSame = 0, c2Same = 0, bothSame2 = 0;
282	        for (int i = 0; i < urls.size(); i++) {
283	            for (int j = i + 1; j < urls.size(); j++) {
284	                boolean s1 = c1.get(urls.get(i)).equals(c1.get(urls.get(j)));
285	                boolean s2 = c2.get(urls.get(i)).equals(c2.get(urls.get(j)));
286	                if (s1) { c1Same++;  if (s2) bothSame++;  }
287	                if (s2) { c2Same++;  if (s1) bothSame2++; }
288	            }
289	        }
290	        double precision = c1Same  == 0 ? 0.0 : (double) bothSame  / c1Same;
291	        double recall    = c2Same  == 0 ? 0.0 : (double) bothSame2 / c2Same;
292	        return new double[]{precision, recall};
293	    }
294	
295	    private double[] bestAggregation(JsonNode partitionRoot, Map<String, String> c2) {
296	        double bestF1 = -1;
297	        double bestPrec = 0, bestRec = 0;
298	        int bestDepth = 1;
299	
300	        int[] depths = {1, 2, 3, 4, 5, 6, 7, -1};
301	        for (int depth : depths) {
302	            Map<String, String> c1All = extractAtDepth(partitionRoot, depth);
303	            List<String> urls = new ArrayList<>(c1All.keySet());
304	            urls.retainAll(c2.keySet());
305	            urls.sort(Comparator.naturalOrder());
306	            if (urls.size() < 2) {
